            {cls._cache_key(e.from_address_id, e.to_address_id): e for e in resolved.values() if e},
            600,
        )
        cache.set_many(
            {
                cls._cache_key(e.from_address_id, e.to_address_id): cls._to_cache_value(e)
                for e in resolved.values()
                if e
            },
            DISTANCE_CACHE_TTL,
        )
        ordered_distances = [resolved.get(addr.id) for addr in from_addresses]
        return [d for d in ordered_distances if d is not None]

    class Meta(OtovoModel.Meta):
        indexes = [
            models.Index(
                fields=['from_address', 'to_address'],
                name='travel_dist_from_ad_570a4b_idx',
            ),
        ]

    def __str__(self) -> str:
